     1→"use client";
     2→
     3→import { useState, useRef, useMemo, useEffect } from "react";
     4→
     5→export default function RecordPage() {
     6→  const [isRecording, setIsRecording] = useState(false);
     7→  const [elapsedSeconds, setElapsedSeconds] = useState(0);
     8→  const [transcript, setTranscript] = useState("");
     9→  const [draft, setDraft] = useState("");
    10→  const [enhanced, setEnhanced] = useState("");
    11→  const [statusText, setStatusText] = useState("Ready to record");
    12→
    13→  const displayStreamRef = useRef<MediaStream | null>(null);
    14→  const micStreamRef = useRef<MediaStream | null>(null);
    15→  const mixedStreamRef = useRef<MediaStream | null>(null);
    16→  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    17→  const recordedChunksRef = useRef<Blob[]>([]);
    18→  const timerRef = useRef<number | null>(null);
    19→
    20→  const timeString = useMemo(() => {
    21→    const m = String(Math.floor(elapsedSeconds / 60)).padStart(2, "0");
    22→    const s = String(elapsedSeconds % 60).padStart(2, "0");
    23→    return `${m}:${s}`;
    24→  }, [elapsedSeconds]);
    25→
    26→  function stopTracks(stream: MediaStream | null) {
    27→    if (!stream) return;
    28→    stream.getTracks().forEach((t) => t.stop());
    29→  }
    30→
    31→  async function startRecording() {
    32→    setTranscript("");
    33→    setEnhanced("");
    34→    recordedChunksRef.current = [];
    35→
    36→    try {
    37→      const displayStream = await navigator.mediaDevices.getDisplayMedia({
    38→        video: true,
    39→        audio: {
    40→          channelCount: 2,
    41→          echoCancellation: false,
    42→          noiseSuppression: false,
    43→          autoGainControl: false,
    44→        },
    45→      });
    46→
    47→      const micStream = await navigator.mediaDevices.getUserMedia({
    48→        audio: {
    49→          channelCount: 1,
    50→          echoCancellation: true,
    51→          noiseSuppression: true,
    52→          autoGainControl: true,
    53→        },
    54→      });
    55→
    56→      displayStream.getVideoTracks().forEach((t) => t.stop());
    57→
    58→      const audioContext = new AudioContext();
    59→      const destination = audioContext.createMediaStreamDestination();
    60→      const displaySource = audioContext.createMediaStreamSource(displayStream);
    61→      const micSource = audioContext.createMediaStreamSource(micStream);
    62→
    63→      displaySource.connect(destination);
    64→      micSource.connect(destination);
    65→
    66→      const mixedStream = destination.stream;
    67→      const mediaRecorder = new MediaRecorder(mixedStream, {
    68→        mimeType: "audio/webm",
    69→      });
    70→
    71→      mediaRecorder.ondataavailable = (e) => {
    72→        if (e.data.size > 0) recordedChunksRef.current.push(e.data);
    73→      };
    74→
    75→      mediaRecorder.start();
    76→
    77→      displayStreamRef.current = displayStream;
    78→      micStreamRef.current = micStream;
    79→      mixedStreamRef.current = mixedStream;
    80→      mediaRecorderRef.current = mediaRecorder;
    81→
    82→      setIsRecording(true);
    83→      setStatusText("Recording...");
    84→      setElapsedSeconds(0);
    85→
    86→      timerRef.current = window.setInterval(() => {
    87→        setElapsedSeconds((prev) => prev + 1);
    88→      }, 1000);
    89→    } catch (error) {
    90→      setStatusText("Failed to start recording");
    91→      console.error(error);
    92→    }
    93→  }
    94→
    95→  function stopRecording() {
    96→    const recorder = mediaRecorderRef.current;
    97→    if (recorder && recorder.state !== "inactive") {
    98→      recorder.stop();
    99→    }
   100→
   101→    if (timerRef.current) {
   102→      window.clearInterval(timerRef.current);
   103→      timerRef.current = null;
   104→    }
   105→
   106→    stopTracks(displayStreamRef.current);
   107→    stopTracks(micStreamRef.current);
   108→    stopTracks(mixedStreamRef.current);
   109→
   110→    setIsRecording(false);
   111→    setStatusText("Recording stopped");
   112→  }
   113→
   114→  async function transcribe() {
   115→    const configStr = localStorage.getItem("ai-provider");
   116→    if (!configStr) {
   117→      alert("Please configure your AI provider in settings first");
   118→      return;
   119→    }
   120→
   121→    const config = JSON.parse(configStr);
   122→
   123→    if (!recordedChunksRef.current.length) {
   124→      alert("No recording found. Please record first.");
   125→      return;
   126→    }
   127→
   128→    setStatusText("Transcribing...");
   129→
   130→    try {
   131→      const audioBlob = new Blob(recordedChunksRef.current, {
   132→        type: "audio/webm",
   133→      });
   134→
   135→      const formData = new FormData();
   136→      formData.append("file", audioBlob, "recording.webm");
   137→      formData.append("provider", config.provider);
   138→      formData.append("apiKey", config.apiKey);
   139→      formData.append("model", config.model);
   140→
   141→      const response = await fetch("/api/transcribe", {
   142→        method: "POST",
   143→        body: formData,
   144→      });
   145→
   146→      if (!response.ok) {
   147→        const error = await response.json();
   148→        throw new Error(error.error || "Transcription failed");
   149→      }
   150→
   151→      const data = await response.json();
   152→      setTranscript(data.text);
   153→
   154→      // Auto-generate draft bullets from first few sentences
   155→      if (!draft.trim()) {
   156→        const bullets = data.text
   157→          .split(". ")
   158→          .map((s: string) => s.trim())
   159→          .filter(Boolean)
   160→          .slice(0, 6)
   161→          .map((s: string) => `- ${s}`)
   162→          .join("\n");
   163→        setDraft(bullets);
   164→      }
   165→
   166→      setStatusText("Transcription complete!");
   167→    } catch (error) {
   168→      console.error("Transcription error:", error);
   169→      setStatusText("Transcription failed");
   170→      alert(error instanceof Error ? error.message : "Transcription failed");
   171→    }
   172→  }
   173→
   174→  // Cleanup on unmount
   175→  useEffect(() => {
   176→    return () => {
   177→      if (timerRef.current) {
   178→        window.clearInterval(timerRef.current);
   179→      }
   180→      stopTracks(displayStreamRef.current);
   181→      stopTracks(micStreamRef.current);
   182→      stopTracks(mixedStreamRef.current);
   183→    };
   184→  }, []);
   185→
   186→  return (
   187→    <div className="min-h-screen bg-zinc-50 dark:bg-zinc-950">
   188→      <div className="container mx-auto max-w-6xl space-y-6 px-4 py-8">
   189→        {/* Header */}
   190→        <header className="flex flex-wrap items-center justify-between gap-6">
   191→          <div>
   192→            <h1 className="text-3xl font-bold text-zinc-900 dark:text-zinc-50">
   193→              New Recording
   194→            </h1>
   195→            <p className="mt-1 text-sm text-zinc-600 dark:text-zinc-400">
   196→              Record Chrome tab audio + microphone
   197→            </p>
   198→          </div>
   199→          <div className="flex items-center gap-3 rounded-full border border-zinc-200 bg-white px-4 py-2 text-sm font-semibold dark:border-zinc-800 dark:bg-zinc-900">
   200→            <span
   201→              className={`h-2 w-2 rounded-full ${
   202→                isRecording
   203→                  ? "animate-pulse bg-red-500"
   204→                  : "bg-zinc-300 dark:bg-zinc-700"
   205→              }`}
   206→            />
   207→            <span className="text-zinc-700 dark:text-zinc-300">
   208→              {statusText}
   209→            </span>
   210→            <span className="text-zinc-500 dark:text-zinc-500">
   211→              {timeString}
   212→            </span>
   213→          </div>
   214→        </header>
   215→
   216→        {/* Instructions */}
   217→        <div className="rounded-lg border border-blue-200 bg-blue-50 px-4 py-3 text-sm text-blue-900 dark:border-blue-900 dark:bg-blue-950 dark:text-blue-100">
   218→          <strong>Before you start:</strong> Choose <strong>Chrome Tab</strong>{" "}
   219→          and enable <strong>Share tab audio</strong> when the browser prompts
   220→          you.
   221→        </div>
   222→
   223→        {/* Controls */}
   224→        <section className="flex flex-wrap items-center gap-3">
   225→          <button
   226→            onClick={startRecording}
   227→            disabled={isRecording}
   228→            className="rounded-lg bg-zinc-900 px-6 py-3 font-medium text-white transition-colors hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed dark:bg-zinc-50 dark:text-zinc-900 dark:hover:bg-zinc-200"
   229→          >
   230→            Start Recording
   231→          </button>
   232→          <button
   233→            onClick={stopRecording}
   234→            disabled={!isRecording}
   235→            className="rounded-lg bg-red-600 px-6 py-3 font-medium text-white transition-colors hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed"
   236→          >
   237→            Stop
   238→          </button>
   239→          <button
   240→            onClick={transcribe}
   241→            disabled={isRecording || recordedChunksRef.current.length === 0}
   242→            className="rounded-lg border border-zinc-300 bg-white px-6 py-3 font-medium text-zinc-900 transition-colors hover:bg-zinc-50 disabled:opacity-50 disabled:cursor-not-allowed dark:border-zinc-700 dark:bg-zinc-900 dark:text-zinc-50 dark:hover:bg-zinc-800"
   243→          >
   244→            Transcribe
   245→          </button>
   246→        </section>
   247→
   248→        {/* Content Grid */}
   249→        <section className="grid gap-6 lg:grid-cols-2">
   250→          {/* Transcript */}
   251→          <div className="rounded-lg border border-zinc-200 bg-white p-6 dark:border-zinc-800 dark:bg-zinc-900">
   252→            <h2 className="mb-4 text-lg font-semibold text-zinc-900 dark:text-zinc-50">
   253→              Transcript
   254→            </h2>
   255→            <div className="max-h-[420px] min-h-[320px] whitespace-pre-wrap text-sm text-zinc-700 dark:text-zinc-300">
   256→              {transcript || "Transcript will appear here after transcription."}
   257→            </div>
   258→          </div>
   259→
   260→          {/* Draft Notes */}
   261→          <div className="rounded-lg border border-zinc-200 bg-white p-6 dark:border-zinc-800 dark:bg-zinc-900">
   262→            <h2 className="mb-4 text-lg font-semibold text-zinc-900 dark:text-zinc-50">
   263→              Draft Notes
   264→            </h2>
   265→            <textarea
   266→              value={draft}
   267→              onChange={(e) => setDraft(e.target.value)}
   268→              placeholder="Type quick notes while you meet..."
   269→              className="mb-4 min-h-[200px] w-full rounded-lg border border-zinc-200 bg-zinc-50 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-zinc-900 dark:border-zinc-700 dark:bg-zinc-800 dark:text-zinc-100 dark:focus:ring-zinc-50"
   270→            />
   271→            <div className="h-px bg-zinc-200 dark:bg-zinc-800" />
   272→            <div className="mt-4">
   273→              <div className="text-xs font-semibold uppercase tracking-wide text-zinc-500 dark:text-zinc-500">
   274→                Enhanced
   275→              </div>
   276→              <div className="mt-2 whitespace-pre-wrap text-sm text-zinc-700 dark:text-zinc-300">
   277→                {enhanced || "Enhanced notes will appear here."}
   278→              </div>
   279→            </div>
   280→          </div>
   281→        </section>
   282→
   283→        {/* Info */}
   284→        <footer className="text-xs text-zinc-500 dark:text-zinc-500">
   285→          Recording stays local in your browser. Configure AI provider in
   286→          settings to transcribe.
   287→        </footer>
   288→      </div>
   289→    </div>
   290→  );
   291→}
